/* ============================================================
   BORNEXA — couche de dossier partagée (Option A)
   Un dossier client unique, partagé entre les 4 outils :
   visite-terrain · calculateur-interne · chantier-installation · documenten-installatie
   Chaque outil PUSH son payload natif et PULL ceux des outils amont.
   => Plus de copier-coller JSON, sans rien perdre des outils.
   ============================================================ */
(function () {
  'use strict';
  var KEY = 'bornexa-dossiers-v1';
  var SEQ = 'bornexa-dossier-seq';

  function read() { try { return JSON.parse(localStorage.getItem(KEY)) || { current: '', dossiers: {} }; } catch (e) { return { current: '', dossiers: {} }; } }
  function write(s) {
    try { localStorage.setItem(KEY, JSON.stringify(s)); return true; }
    catch (e) { // quota dépassé -> on retire les photos de visite (les plus lourdes) puis on réessaie
      try { var c = JSON.parse(JSON.stringify(s)); Object.keys(c.dossiers).forEach(function (k) { var d = c.dossiers[k]; if (d.visite && d.visite.photos) delete d.visite.photos; }); localStorage.setItem(KEY, JSON.stringify(c)); return true; }
      catch (e2) { return false; }
    }
  }
  function nextSeq() { var n = parseInt(localStorage.getItem(SEQ) || '0', 10) + 1; localStorage.setItem(SEQ, String(n)); return n; }
  function makeId() { return 'BX-' + new Date().getFullYear() + '-' + String(nextSeq()).padStart(4, '0'); }

  var S = read();
  function persist() { write(S); }
  function active() { return S.current && S.dossiers[S.current] ? S.dossiers[S.current] : null; }

  var Bornexa = {
    KEY: KEY,
    reload: function () { S = read(); },
    list: function () { return Object.keys(S.dossiers).map(function (k) { return S.dossiers[k]; }).sort(function (a, b) { return (b.updated || 0) - (a.updated || 0); }); },
    currentId: function () { return S.current; },
    active: active,
    has: function () { return !!active(); },
    setCurrent: function (id) { if (S.dossiers[id]) { S.current = id; persist(); } },
    create: function (name) {
      var id = makeId();
      S.dossiers[id] = { id: id, name: name || '', status: 'Nouveau', created: Date.now(), updated: Date.now() };
      S.current = id; persist(); return id;
    },
    rename: function (id, name) { if (S.dossiers[id]) { S.dossiers[id].name = name; S.dossiers[id].updated = Date.now(); persist(); } },
    del: function (id) { delete S.dossiers[id]; if (S.current === id) S.current = Object.keys(S.dossiers)[0] || ''; persist(); },
    duplicate: function (id) {
      var d = S.dossiers[id]; if (!d) return null;
      var nid = makeId(), copy = JSON.parse(JSON.stringify(d));
      copy.id = nid; copy.name = (d.name || 'Dossier') + ' (copie)'; copy.created = copy.updated = Date.now(); copy.status = d.status;
      S.dossiers[nid] = copy; S.current = nid; persist(); return nid;
    },
    // type ∈ 'visite' | 'devis' | 'chantier' | 'docs'
    put: function (type, payload) {
      var a = active(); if (!a) return false;
      a[type] = payload; a.updated = Date.now();
      if (type === 'visite' && payload && payload.data && payload.data.clientName && !a.name) a.name = payload.data.clientName;
      if (type === 'devis' && payload && payload.client && payload.client.name && !a.name) a.name = payload.client.name;
      var rank = { Nouveau: 0, Visite: 1, Devis: 2, Chantier: 3, Documents: 4 };
      var st = { visite: 'Visite', devis: 'Devis', chantier: 'Chantier', docs: 'Documents' }[type];
      if (st && (rank[st] || 0) >= (rank[a.status] || 0)) a.status = st;
      persist(); return true;
    },
    get: function (type) { var a = active(); return a ? (a[type] || null) : null; },
    exportActive: function () { return active(); },
    importDossier: function (obj) { if (!obj || !obj.id) { if (obj) { obj.id = makeId(); } else return null; } S.dossiers[obj.id] = obj; S.current = obj.id; obj.updated = Date.now(); persist(); return obj.id; },
    // Sauvegarde COMPLÈTE : tous les dossiers + dossier courant (pour backup / transfert de PC)
    exportAll: function () { return { schema: 'bornexa-backup-v1', exportedAt: Date.now(), current: S.current, dossiers: S.dossiers }; },
    // Restauration : 'merge' (fusionne, garde les dossiers existants) ou 'replace' (remplace tout)
    importAll: function (obj, mode) {
      if (!obj || !obj.dossiers) return 0;
      if (mode === 'replace') S.dossiers = {};
      var n = 0;
      Object.keys(obj.dossiers).forEach(function (k) { S.dossiers[k] = obj.dossiers[k]; n++; });
      if (obj.current && S.dossiers[obj.current]) S.current = obj.current;
      persist(); return n;
    }
  };
  window.Bornexa = Bornexa;

  /* ============================================================
     SIGNATURE SOCIÉTÉ — point UNIQUE de configuration
     Pour changer la signature : remplace le fichier images/signature-bornexa.png
     Pour ajuster la taille : modifie 'height' (px) ci-dessous (ou par appel).
     PNG transparent recommandé, haute résolution (≈ 800–1600 px de large)
     pour rester net à l'impression PDF.
     ============================================================ */
  Bornexa.signature = {
    src: 'data:image/png;base64,', // signature embarquee (base64) - aucun fichier externe a deployer
    height: 52                            // hauteur d'affichage par défaut (px)
  };

  // Clé localStorage SCOPÉE au dossier actif : empêche un nouveau/autre dossier
  // d'hériter des données (formulaire) du dossier précédent. Hors dossier → clé de base.
  Bornexa.scopedKey = function (base) {
    return (S.current && S.dossiers[S.current]) ? (base + '::' + S.current) : base;
  };

  // Injecte la signature dans un conteneur (image absente = rien ne s'affiche)
  Bornexa.injectSignature = function (el, height) {
    if (!el || !Bornexa.signature.src) return;
    el.innerHTML = '';
    var img = document.createElement('img');
    img.alt = 'Signature BORNEXA';
    img.style.cssText = 'height:' + (height || Bornexa.signature.height) + 'px;width:auto;max-width:100%;display:block;object-fit:contain';
    img.onerror = function () { el.innerHTML = ''; }; // pas de fichier → boîte vide (signature manuscrite possible)
    img.src = Bornexa.signature.src;
    el.appendChild(img);
  };

  /* Bandeau « dossier actif » injecté dans les 4 outils (data-bornexa-tool sur <body>) */
  document.addEventListener('DOMContentLoaded', function () {
    var tool = document.body.getAttribute('data-bornexa-tool');
    if (!tool) return;
    /* Le bandeau ne doit JAMAIS apparaître à l'impression / PDF (outil interne) */
    var st = document.createElement('style');
    st.textContent = '@media print{#bornexa-dossier-bar{display:none !important}}';
    document.head.appendChild(st);
    var a = active();
    var bar = document.createElement('div');
    bar.id = 'bornexa-dossier-bar';
    bar.className = 'no-print';
    bar.style.cssText = 'position:sticky;top:0;z-index:9998;background:' + (a ? '#0B1E3C' : '#92400E') + ';color:#fff;font-size:.82rem;font-weight:600;padding:7px 14px;display:flex;align-items:center;gap:10px;justify-content:center;flex-wrap:wrap';
    bar.innerHTML = a
      ? '📁 Dossier actif : <b style="color:#1ADBA8">' + (a.id) + (a.name ? ' · ' + escapeHtml(a.name) : '') + '</b> <span style="opacity:.6">(' + (a.status || '') + ')</span> · <a href="bornexa-hub" style="color:#1ADBA8;text-decoration:underline">Hub</a>'
      : '⚠ Aucun dossier actif — les données ne seront pas centralisées. <a href="bornexa-hub" style="color:#fff;text-decoration:underline">Ouvrir le hub</a>';
    document.body.insertBefore(bar, document.body.firstChild);
  });
  function escapeHtml(s) { return String(s == null ? '' : s).replace(/[&<>"]/g, function (c) { return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]; }); }
})();
